var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……그래서 성탄제를 열고 싶다는 말씀인가요?","JPN":"……それで、聖誕祭の行事を行いたいということですか？","ENG":"...So, you wish to host a Christmas party?","TWN":"……所以你是說想要舉辦聖誕節活動嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네, 루체 자매님.","JPN":"はい、シスター・ルーチェ。","ENG":"Yes, Sister Luce.","TWN":"是的，露契姊妹。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"작년 성탄절은 성무 때문에 아쉽게도 그냥 넘어갔거든요.","JPN":"昨年の聖誕祭は残念ながら、聖務でお祝いできませんでしたので。","ENG":"We couldn't celebrate it last year due to the sacred mission.","TWN":"去年的聖誕節因為聖務的關係，遺憾地就這樣過去了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"올해는 그간 신세 졌던 분들을 초대해서 다 함께 성탄절을 보내는 게 어떨까 해서요.","JPN":"今年は今までお世話になった方々を招待して、一緒に聖誕祭を過ごすのはどうでしょうか？","ENG":"But this year, I was thinking of inviting everyone we're thankful for and spending Christmas altogether.","TWN":"今年我想邀請那些一直以來幫助過我們的人，一起過聖誕節。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성탄절이라면 시스터 루퍼가 때마침 사제 심사를 마치고 돌아오는 날이로군요.","JPN":"聖誕祭ならシスター・ルーパーがちょうど司祭審査を終えて帰ってくる日ですね。","ENG":"Also, it just so happens that Christmas is when Sister Looper returns from her priest evaluation.","TWN":"聖誕節的話，也正好是洛珀姊妹完成考核歸來之日呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……아주 우연하게도 말이죠.","JPN":"……偶然ながら。","ENG":"...How coincidental.","TWN":"……那真是不巧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아하하… 그, 그랬나요?","JPN":"あはは……そ、そうでしたか？","ENG":"Ah hah hah... I-is it?","TWN":"啊哈哈……是、是這樣嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그, 그렇지! 그럼, 성탄제에서 루퍼 자매님의 서품 축하를 겸하면 어떨까요?","JPN":"そ、そう！　じゃあ、聖誕祭でシスター・シンディの叙階も一緒に祝うのはどうですか？","ENG":"R-right! So, how about we celebrate Sister Looper's ordination on Christmas too?","TWN":"那、那就這樣吧！那麼，在聖誕節上順便慶祝洛珀姊妹的授職儀式怎麼樣？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"글쎄요, 이상한 대목이네요.","JPN":"さあ、それはどうでしょうか。","ENG":"Well, that seems a bit strange.","TWN":"這個嘛，有些古怪。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 루퍼가 반드시 심사에 통과한다는 보장이 없을 텐데요?","JPN":"シスター・ルーパーが必ずしも審査で合格するという保証はないはずです。","ENG":"There is no guarantee that Sister Looper will pass.","TWN":"洛珀不一定能通過考核吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"우, 우으… 그건, 그렇지만…….","JPN":"う、うう……それは、そうですけど……","ENG":"U-um... B-but still–","TWN":"唔、唔呃……那、那是，可是……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"후우, 역시 루체 자매님은 못 속이겠어요.","JPN":"ふう、やはりシスター・ルーチェは騙せません。","ENG":"*Sigh* I guess there's no fooling Sister Luce.","TWN":"呼，果然是無法欺騙露契姊妹啊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사실은 루퍼 자매님에게 특별한 추억을 만들어 주고 싶거든요.","JPN":"実はシスター・シンディに特別な思い出を作ってあげたいのです。","ENG":"In truth, I wanted to create a special memory for Sister Looper.","TWN":"其實是想給洛珀姊妹留下特別的回憶。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"추억이라고요?","JPN":"思い出ですか？","ENG":"A special memory?","TWN":"回憶嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 왜냐하면 루퍼 자매님은 한 번도 제대로 된 성탄절을 맞이한 적이 없을 테니까요.","JPN":"はい。だって、シスター・シンディは一度もちゃんとした聖誕祭を迎えたことがないでしょうから。","ENG":"Yes. Because she has never properly celebrated Christmas before.","TWN":"是的，因為洛珀姊妹從來沒有過一個真正的聖誕節。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……성무 수행을 위해, CSE 레벨 3 침식 지대에 도착했을 때, 자매님은 혼자였어요.","JPN":"……聖務遂行のためにCSEレベル3の侵食地帯に着いた時、シスター・シンディは1人だったんです。","ENG":"...When I arrived at the CSE Level 3 Corrupted Area for my sacred mission, she was all alone.","TWN":"……為了執行聖務，當到達CSE等級3的侵蝕地帶時，她也一直是一個人。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사교도의 지하실에서 홀린 듯, 홀로 공포 영화를 보고 있었죠.","JPN":"邪教徒の地下室でとり憑かれたように、1人でホラー映画を見ていました。","ENG":"And I saw her watching a horror movie by herself in the cultist's basement as if she was possessed.","TWN":"在邪教徒的地下室裡，像著了魔一樣，獨自看恐怖電影。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"널브러진 침식체 사체들 한 가운데서 피투성이가 된 채로…….","JPN":"累々と横たわる侵食体の屍の真ん中で血まみれになったまま……","ENG":"She was covered in blood, surrounded by scattered C.O. corpses...","TWN":"在散落著侵蝕體屍體中間，渾身是血……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님을 감금했던 사교도들은 보육원으로 위장하여 인권 유린을 저질러왔다고 해요.","JPN":"シスター・シンディを監禁した邪教徒たちは、養護施設と偽装して人権を蹂躙してきたそうです。","ENG":"The cult that imprisoned her committed human rights violations under the guise of an orphanage.","TWN":"據說那些邪教徒，綁架她後，偽裝成孤兒院的工作人員虐待她。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"성무 보고서에는 CSE에 의한 정신 착란이 있었다고 쓰여있었지만.","JPN":"聖務報告書には、CSEによる精神錯乱だと書かれていたんですが。","ENG":"The sacred mission report stated that she had delirium due to CSE, but...","TWN":"聖務報告中寫到，是由CSE引發的精神錯亂。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"정작, 현장에서 구조된 루퍼 자매님의 정신 감정 결과는 이상이 없다고 밝혀졌죠.","JPN":"現場から救助されたシスター・シンディの精神鑑定結果は異常なしということがわかったのです。","ENG":"When Sister Looper had her mental health examined after being rescued, the results showed no abnormalities.","TWN":"事實上，精神鑒定結果顯示，現場獲救的洛珀姊妹精神沒有異常。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아시다시피, 사교도들에 의해 자행된 인권 유린이 꼭 CSE 탓일 리는 없습니다.","JPN":"ご存じでしょうが、邪教徒たちによって行われた人権蹂躙が必ずしもCSEのせいだとは限りません。","ENG":"As you know, the human rights violations committed by the cult cannot necessarily be blamed on CSE.","TWN":"如你所知，由邪教徒們實施的虐待不一定都是CSE的錯。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오히려 인간의 무의식적인 감정 변화가 침식 현상에 영향을 준다는 연구 결과도 있죠.","JPN":"むしろ、人間の無意識の感情変化が侵食現象に影響するという研究結果もあります。","ENG":"Rather, there is research that shows that the subconscious emotional change in humans can affect the Counterside Effect.","TWN":"反而有研究結果表明，人類無意識的情感變化會影響侵蝕現象。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"맞아요. 하지만 그렇다는 말은…….","JPN":"そうです。でも、それはつまり……","ENG":"Yes. But then, that means...","TWN":"話是這樣沒錯，那就是說……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루퍼 자매님은 그곳에서 수년간을 맨정신으로 버텨왔다는 뜻이잖아요.","JPN":"シスター・シンディはあそこで数年間、はっきりとした精神で耐えてきたという意味ではないですか。","ENG":"Sister Looper has spent years there without going insane.","TWN":"洛珀姊妹在那邊以清醒的狀態度過了好幾年？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아무리 강한 척해도 아직은 어린아이일 뿐인데… 가엾게도…….","JPN":"いくら強がっていてもまだ子どもなのに……可哀想に……","ENG":"No matter how tough she acts, she is still just a child... That poor thing...","TWN":"無論怎麼裝腔作勢，但她終究還是個孩子……太可憐了……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사람은 추억을 먹고 산다고도 하잖아요?","JPN":"人間は思い出に生かされるっていうでしょう？","ENG":"They say people live by memories, right?","TWN":"人們不是說人是靠回憶活著的嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그러니… 루퍼 자매님을 너그러이 용서해 주시면 안 될까요?","JPN":"ですから……シスター・シンディのことは大目に見ていただけませんか？","ENG":"So... would it be possible for you to generously forgive Sister Looper?","TWN":"所以……能不能寬恕洛珀姊妹呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"올해는 자매님께 <color=#ffd34c>특별한 성탄절</color>을 선물해 드리고 싶거든요.","JPN":"今年はシスター・シンディに<color=#ffd34c>特別な聖誕祭</color>をプレゼントしたいです。","ENG":"This year, I want to give her a <color=#ffd34c>special Christmas</color>.","TWN":"今年我想送給她一個<color=#ffd34c>特別的聖誕節</color>禮物。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"어른이 돼서도, 언제까지나 가슴 속에 남을 수 있는 행복한 추억을.","JPN":"大人になっても、いつまでも心の中に残る幸せな思い出を。","ENG":"A happy memory that she will cherish well into her adulthood.","TWN":"即使長大成人，也能永遠留在心中的幸福回憶。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해드리죠, 시스터 넬슨. 공과 사는 철저히 구분되어야만 합니다.","JPN":"喜んで訂正いたします、シスター・ネルソン。公私は徹底的に分けるべきだと思います。","ENG":"I would be more than happy to rephrase, Sister Nelson. Personal and professional matters must be kept strictly separate.","TWN":"我要更正一下，尼爾森姊妹。公私必須嚴格分開。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저는 주께서 부여한 책무에 결코 사사로운 감정을 개입하지 않죠.","JPN":"私は主から与えられた責務に決して私情を持ち込みません。","ENG":"I do not let my emotions get involved in the responsibilities our Lord has given me.","TWN":"我絕不會將個人情感摻入主賦予的職責中。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그렇다는 말씀은……","JPN":"ということは……","ENG":"What you're saying is...","TWN":"那就是說……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 주께서 이르기를, 행복은 나누면 배가 된다고도 하셨습니다.","JPN":"ですが主曰く、幸せは分かち合えば倍になるともおっしゃいました。","ENG":"But the Lord has also said that happiness is multiplied when shared.","TWN":"但是主說過，幸福在分享後是會加倍的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"따라서 그간 신세 졌던 이들을 초대하여 작은 연회를 갖는 건 나쁘지 않군요.","JPN":"ですので、今までお世話になった人たちを招待してささやかな宴会を催すのは悪くありませんね。","ENG":"Thus, a small banquet with everyone we owe a debt of gratitude does not sound like a bad idea.","TWN":"因此，邀請那些一直以來幫助過我們的人舉辦一個小型宴會，這樣也不錯。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"공적인 관계일수록, 적당한 체면치레는 중요한 법이니까.","JPN":"公的な関係であるほど、適度に義理立てすることも大事ですからね。","ENG":"It is important to maintain proper respect in professional relations.","TWN":"越是公事公辦，適當的面子功夫就越重要。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루체 자매님……!","JPN":"シスター・ルーチェ……！","ENG":"Sister Luce...!","TWN":"露契姊妹……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"단, 이 일은 성탄제 당일까지 시스터 루퍼에게 알리지 말도록 하세요.","JPN":"ただし、このことは聖誕祭当日までシスター・ルーパーには内緒にしてください。","ENG":"However, do not tell Sister Looper about this until Christmas Day.","TWN":"不過，這件事在聖誕節當天到來之前，請不要告訴洛珀姊妹。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"사제 심사까지 며칠 남지 않았습니다.","JPN":"司祭審査まであと数日しかありません。","ENG":"Her priest evaluation is in a few days.","TWN":"距離祭司考核只剩幾天了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이제야 조금 열심히 하기 시작했는데, 괜히 들떠서 일을 그르칠 것 같아 걱정되는군요.","JPN":"やっと少しは努力するようになったのに、浮かれて台無しになるのではないかと心配なんです。","ENG":"She has just started to put in effort, and I worry that she will get too excited and neglect her duties.","TWN":"她才開始認真起來，我擔心會因為過於興奮把事情搞砸。。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"무, 물론이에요! 루퍼 자매님께는 비밀로 할게요!","JPN":"も、もちろんです！　シスター・シンディには内緒にします！","ENG":"O-of course! I'll keep it a secret from Sister Looper!","TWN":"當、當然了！我會對洛珀姊妹保密的！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"훗, 본의 아니게 시스터 루퍼에게는 서프라이즈 파티가 되겠군요.","JPN":"ふっ、不本意ながらシスター・ルーパーにはサプライズパーティーになりますね。","ENG":"Hah, it seems that this will be a surprise party for Sister Looper.","TWN":"呵，莫名其妙就要替洛珀姊妹辦驚喜派對。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저… 신경 써주셔서 감사해요.","JPN":"あの……お気遣いありがとうございます。","ENG":"Um... Thank you for understanding.","TWN":"那個……感謝你的幫助。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사실, 자매님께서 이렇게 흔쾌히 허락해 주실 줄은 몰랐거든요.","JPN":"実は、シスター・ルーチェが快諾してくれるとは思ってなかったのです。","ENG":"To be honest, I didn't expect you to allow it this easily.","TWN":"其實，我沒想到你會這麼爽快地答應。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루퍼 자매님을 싫어하시는 줄 알았는데…….","JPN":"シスター・シンディが嫌いなんだと思っていたのですが……","ENG":"I thought you didn't like Sister Looper...","TWN":"我還以為你不喜歡洛珀姊妹呢……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……크흠.","JPN":"……ゴホン。","ENG":"...Ahem.","TWN":"……咳嗯。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"좋아하지 않습니다. 시스터 루퍼는 비이성적이고, 폭력적이며, 무식하기까지 하니까요.","JPN":"好きではありません。シスター・ルーパーは非理性的で暴力的な上、無知ですから。","ENG":"I do not. Sister Looper is irrational, violent, and ignorant.","TWN":"確實不喜歡。洛珀姊妹既不理性，又暴力，還很無知。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그저, 선배로서 하룻강아지 시스터가 하루 빨리 조숙해지길 바랄 뿐이죠.","JPN":"ただ、先輩としてひよっこシスターが一日でも早く大人になってほしいだけです。","ENG":"All I can hope for as her senior is that she matures quickly with each passing day.","TWN":"只是，作為前輩，希望小小的修女能早日成熟起來。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"후후, 네. 이 또한 자비로운 주님께서 베푸신 은총이겠죠.","JPN":"ふふ、はい。これもまた慈しみ深い神の恵なのでしょう。","ENG":"Haha. This too must be a blessing from the merciful Lord.","TWN":"呵呵，是啊，這也是仁慈的主賜予的恩典吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그럼, 성탄제의 장소와 손님들의 초대 그리고 파티 요리까지… 전부 제게 맡겨주세요.","JPN":"では聖誕祭の場所とお客さまの招待、そしてパーティーの料理まで……全部私に任せてください。","ENG":"Then, leave everything to me... from choosing the party location, inviting our guests, and preparing the food.","TWN":"那麼，聖誕節宴會的場地、客人的邀請以及派對的料理……全部交給我吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"모두가 즐거운 성탄절이 될 수 있도록, 저 힘내서 준비할 테니까요……!","JPN":"皆さんが楽しい聖誕祭になるように私、頑張って準備します……！","ENG":"I'll do my best so everyone can have a happy Christmas...!","TWN":"為了讓大家都能度過一個愉快的聖誕節，我會努力準備的……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네. 성탄제 기대하겠습니다, 시스터 넬슨.","JPN":"はい。聖誕祭、楽しみにしています。シスター・ネルソン。","ENG":"Yes. I look forward to the party, Sister Nelson.","TWN":"好，我會期待這次宴會的，尼爾森姊妹。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"잠깐, 요리라고……?","JPN":"待って、料理って……？","ENG":"Hold on, preparing food...?","TWN":"等等，做料理……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"용케도 그들을 따라갔군요. 그래서 당신은 그 마을에서 뭘 봤죠?","JPN":"よくついて行きましたね。それで、あなたはあの村で何を見たのですか？","ENG":"So you actually followed them. What did you see within the village?","TWN":"結果你們就這樣跟去嗎？所以你看到什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"의외로 별건 없었어.","JPN":"意外と大したことはなかったよ。","ENG":"There wasn't much, to be honest.","TWN":"完全出乎意料，什麼也沒看到。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어떤 놈들은 춤을 추며 노래 부르고, 어떤 놈들은 미친 듯이 땅바닥에 무언가를 그리고 있고, 또 어떤 놈들은 구석에서 요리를 준비하고 있고.","JPN":"あるやつは踊りながら歌って、あるやつは地面に狂ったように何かを描いて、またあるやつは隅っこで料理の準備をして。","ENG":"Some were singing and dancing. Others were drawing something in dirt. And one was preparing food in the corner.","TWN":"有些人在唱歌跳舞，有些人好像發瘋一樣，不知道在地上畫什麼，有些人在一旁準備食物。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"멀리서 봤으면, 진짜 마을 축제인 줄 알겠더라.","JPN":"遠くから見れば、本当に村祭りに見えたかもね。","ENG":"Anyone would've guessed it was a festival from far away.","TWN":"遠看的話，就好像正常的慶典一樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"가까이서 보면?","JPN":"近くで見ると？","ENG":"But up close?","TWN":"那近看呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"녀석들이 먹으라고 내준 수프에 왕꿈틀이가 가득했어.","JPN":"やつらが食べろって出したスープに大王ミミズがいっぱい入ってた。","ENG":"The soup these people were eating was full of those big wigglers.","TWN":"他們端給我們喝的湯裡全都是大蚯蚓。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>클로디아가 그걸 봤어야 쇼크 먹고 주방에 안 들어갈 텐데.</color>","JPN":"<color=#ffd34c>クラウディアが見ればショックでキッチンに入らなくなるのになあ。</color>","ENG":"<color=#ffd34c>I should've shown that to Claudia, then she’d never go back in the kitchen.</color>","TWN":"<color=#ffd34c>克勞迪婭看到的話，應該會嚇到不敢進廚房吧？</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"넬슨의 이력에는 봉사활동 경험도 많았어. 어쩌면 꼬맹이 특유의 괴상한 비유법일지도.","JPN":"ネルソンの履歴にはボランティアの経験も多かった。もしかしたら、子ども特有の言葉のあやかも。","ENG":"Nelson's resume included a lot of volunteer experience. Maybe it is one of those weird metaphors the kid uses.","TWN":"尼爾森的履歷中有很多志工服務的經驗。也許這是小鬼特有的比喻方式吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"뭐, 괜한 걱정이겠지. 아무래도 음식은 맛보다 정성일 테니까.","JPN":"まあ、余計な心配でしょう。食べ物は味より真心だから。","ENG":"Well, I guess it is nothing to worry about. After all, food is about the effort that is put in rather than its taste.","TWN":"嗯，可能是我多慮了。畢竟食物更重要的是用心，而不是味道。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>의심할 수 없을 때까지 의심하라.</color>","JPN":"<color=#ffd34c>疑えなくなるまで疑え。</color>","ENG":"<color=#ffd34c>Doubt until thou cannot doubt any more</color>.","TWN":"<color=#ffd34c>不斷懷疑，直到你無法懷疑為止。</color>"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"머지않아, 이 젊은 사서는 깨닫게 된다.","JPN":"間もなく、この若き司書は気付くことになる。","ENG":"Before long, this young librarian would come to realize","TWN":"不久之後，這位年輕的管理員將會意識到。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"문득, 스쳐 지나간 집행 사제로서의 직감이 결코 기우가 아니었다는 것을…….","JPN":"ふと頭の中をよぎった執行司祭としての直感が、決して杞憂ではなかったということを……","ENG":"that the intuition that she had as an Inquisitorial Priest was not unfounded...","TWN":"突然間，作為治理祭司的直覺告訴我，這絕不是杞人憂天……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>며칠 뒤</color>","JPN":"<color=#ffd34c>数日後</color>","ENG":"<color=#ffd34c>A few days later</color>","TWN":"<color=#ffd34c>幾天後</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>\\n<color=#ffd34c>프리드웬 기관</color> 제3지부, 응접실","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>\\n<color=#ffd34c>プリドウェン機関</color>第3支部・応接室","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>\\n<color=#ffd34c>Prydwen Institution</color> 3rd Branch, Reception room","TWN":"管理局直轄市<color=#ffd34c>查雷德</color>\\n<color=#ffd34c>普利多溫機關</color> 第三分部,接待室"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이거, 기다리게 해서 죄송합니다.","JPN":"これはこれは、お待たせして申し訳ございません。","ENG":"I apologize for keeping you waiting.","TWN":"這個，讓你久等了，抱歉。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"오랜만이로군요. 넬슨 수녀님. 그간 잘 지내셨습니까?","JPN":"お久しぶりです、シスター・ネルソン。お元気でしたか？","ENG":"It has been a while, Sister Nelson. How have you been faring?","TWN":"好久不見了，尼爾森姊妹。最近過得好嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"물론이에요. 페리어 님도 평안하셨나요?","JPN":"もちろんです。フェリエーさんもお変わりありませんか？","ENG":"Good. How have you been, Mr. Ferrier?","TWN":"當然了，佩里先生你也安好嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 그냥 라이언이라고 편하게 부르셔도 괜찮습니다.","JPN":"はは、ライアンとお呼びください。","ENG":"Haha, you can just call me Ryan.","TWN":"哈哈，叫我瑞安就好。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 심의회의 수녀님께서 기관에는 어쩐 일로…….","JPN":"ところで審議会のシスターがどうして機関に……？","ENG":"But what brings a Sister from the Investigation Council to the Institution...?","TWN":"不過，議會的修女怎麼會來這呢……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"아, 다름이 아니라… 기관장님께 이걸 전달해드리려고요.","JPN":"あ、それは……機関長にこれをお渡ししようと思って。","ENG":"Oh, nothing much... I'm here to deliver this to the Chief.","TWN":"啊，不為別的……我是想把這個交給機關長。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이건… 초대장이로군요.","JPN":"これは……招待状ですか。","ENG":"This is... an invitation.","TWN":"這是……邀請函。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"네. 이번 성탄절을 맞아, 저희 심의회가 작은 성탄제를 준비하고 있거든요.","JPN":"はい。今回の聖誕祭に、私たち審議会がささやかな行事を準備しているのです。","ENG":"Yes. This Christmas, the Investigation Council is holding a small Christmas party.","TWN":"是的，為了迎接今年的聖誕節，我們的議會正在準備一個小型聖誕宴會。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"오래전부터 기관의 버넷 경과 요한 추기경께서는 막역한 사이셨다고 들었습니다.","JPN":"昔から機関のバーネット卿とヨハン枢機卿は大変親しい間柄であったと聞きました。","ENG":"I heard that Sir Burnett of the Institution and Cardinal Johan had long been close friends.","TWN":"我聽說很久以前是伯先生和約翰樞機主教是莫逆之交。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그러니 성탄제를 연다면, 가장 먼저 기관 분들을 찾아봬야 한다고 생각했어요.","JPN":"ですから最初に機関の方々を訪ねるべきだと思ったんです。","ENG":"So, I thought that if we were to host a Christmas party, this first thing I should do is make a visit to the Institution.","TWN":"所以我認為如果要舉辦聖誕節宴會，首先應該拜訪機關的各位。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 이거 영광이로군요.","JPN":"ふふ、それは光栄ですね。","ENG":"Haha, this is an honor.","TWN":"呵呵，這是我的榮幸。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"성황청으로부터 초대를 받다니, 아가씨께서도 무척 기뻐하실 겁니다.","JPN":"聖皇庁からの招待とは、お嬢様も大変喜ぶでしょう。","ENG":"An invitation from Holy Curia. I am sure Lady Elizabeth will be thrilled.","TWN":"受到聖皇廳的邀請，小姐也會非常高興的。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"저, 그런데 기관장님께서는……?","JPN":"あの、ところで機関長は……？","ENG":"But um... where might Chief be...?","TWN":"那、那機關長……？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 아가씨께서는 잠시 가출… 크흠! 아니, 외출하셨습니다.","JPN":"ああ、お嬢様はしばらく家出……コホン！　いいえ、お出かけ中です。","ENG":"Lady Elizabeth has run away from ho– Ahem! I mean, is out of the office for the time being.","TWN":"小、小姐暫時離家出走……咳咳！不，是外出了。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 걱정하지 마십시오. 이 초대장은 아가씨께 반드시 전해드릴 테니까요.","JPN":"ですが、ご心配いりません。この招待状は必ずお嬢様にお渡しします。","ENG":"Not to worry. I will make sure she receives this invitation.","TWN":"但是請不要擔心，這份邀請函我一定會轉交給小姐的。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"네, 그럼 부탁드릴게요. 라이언.","JPN":"はい、ではよろしくお願いします。ライアン。","ENG":"Okay. In that case, please give it to her, Ryan.","TWN":"好的，那就拜託你了，瑞安。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이런! 그러고 보니, 귀한 손님께서 오셨는데 홍차에 곁들일 디저트를 잊고 있었군요.","JPN":"おっと！　そういえば、大事なお客様に紅茶と一緒に召し上がるデザートを出すのを忘れていましたね。","ENG":"Drats! Come to think of it, I forgot to bring out desserts that go with this tea for our guest.","TWN":"哎呀！這麼一說，貴客來了，我竟然忘了準備配紅茶的甜點了。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"디저트라고요?","JPN":"デザートですか？","ENG":"Desserts?","TWN":"甜點？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"무릇, 좋은 인연에는 향긋한 홍차와 달콤한 디저트를 빼놓을 수 없는 법이죠.","JPN":"よき出会いには香り高い紅茶と甘いデザートが欠かせないものです。","ENG":"Of course, a good relationship cannot be cherished without fragrant black tea and sweet desserts.","TWN":"凡是有美好的緣分結下，都少不了香醇的紅茶和甜美的甜點。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"잠시 기다려 주시겠습니까.","JPN":"しばらくお待ちください。","ENG":"Could you please wait a moment?","TWN":"請稍等一下。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이 라이언, 오랜만에 솜씨를 발휘해 보이겠습니다.","JPN":"このライアン、久しぶりに実力を発揮するといたしましょう。","ENG":"I, Ryan, shall swiftly make you something delicious.","TWN":"這次就讓我瑞安，好好展示一下我的本事吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다. 자, 사양 말고 드셔 보시죠.","JPN":"お待たせいたしました。さあ、遠慮せずにどうぞ。","ENG":"Thank you for waiting. Now, please don't hesitate to take a bite.","TWN":"久等了。來，別客氣，嚐嚐吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L43_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"이건 비스킷인가요? 버터 향이 향기롭네요.","JPN":"これはビスケットですか？　バターの香りが香ばしいですね。","ENG":"Are these biscuits? The butter in it smells so good.","TWN":"這是餅乾嗎？奶油香味真好聞啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L44_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"영국의 대표적인 디저트인 스콘입니다. 홍차와 곁들일 때 가장 잘 어울리죠.","JPN":"イギリスの代表的なデザート、スコーンです。紅茶のお供にもっとも合うお菓子です。","ENG":"It is a scone, a popular English dessert. It goes best with tea.","TWN":"這是英國的代表性甜點司康。最適合搭配紅茶一起享用。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"으음……?","JPN":"あれ……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"무척 바삭하네요! 홍차와 곁들이면 좋을 것 같아요! 같이 나온 과일 잼도 상큼하고요!","JPN":"とてもサクッとしています！　紅茶と一緒にいただくと良さそうですね！　セットの果物のジャムもさっぱりとしています！","ENG":"It's so crispy! It really does go great with tea! And the fruit jam served with it is delightful!","TWN":"非常酥脆呢！配上紅茶會很不錯喔！一起搭配的水果醬也很清爽呢！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"훌륭해요! 이렇게 맛있는 빵을 구울 수 있다니!","JPN":"すごいです！　こんなに美味しいパンを焼けるなんて！","ENG":"You have outdone yourself! I didn't know you could bake such delicious bread!","TWN":"太棒了！居然能烤出這麼好吃的麵包！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 안목이 높이시군요. 잘 구워서 한 김 식힌 스콘은 바삭해서 맛이 좋죠.","JPN":"ふふ、お目が高い。しっかりと焼いて少し冷ましたスコーンはサクッとしてとても美味しいのですよ。","ENG":"Haha, you have great insight. A well baked, then cooled scone is crispy and delicious.","TWN":"呵呵，你真識貨。剛烤好稍微放涼的司康，酥脆可口，味道極佳。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"개인적으로는 계란을 넣지 않고, 반죽의 결이 살아있는 드라이한 식감을 추구합니다.","JPN":"私は卵を入れず、生地の層が感じられるドライな食感を追及しています。","ENG":"I prefer not to add eggs because it brings out the dry texture of the dough.","TWN":"我個人喜歡不加雞蛋，追求麵團紋理鮮明的乾爽口感。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"라이언 씨는 어떻게 이런 레시피를 알고 있는 건가요?","JPN":"ライアンさんは、どうやってこんなレシピを知ったのですか？","ENG":"Ryan, how did you get your hands on such a recipe?","TWN":"瑞安先生是怎麼知道這種食譜的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 아가씨의 까다로운 입맛을 맞추기 위해, 부단히 노력한 결과라고 할 수 있죠.","JPN":"ふふ、こだわりの強いお嬢様のお口に合うように絶え間なく努力した結果と言えるでしょう。","ENG":"Haha, Lady Elizabeth is a rather picky eater, so you can say these are the results of my constant efforts to satisfy her.","TWN":"呵呵，為了迎合小姐挑剔的口味，我可是下了不少功夫呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"양식 조리사, 중식 조리사, 일식 조리사, 파티시에 마스터, 쇼콜라티에 마스터까지…….","JPN":"西洋料理、中華料理、和食、パティシエマスター、ショコラティエマスター……","ENG":"I have certifications for Western, Chinese, and Japanese cuisine, as well as master-level patisserie and chocolatier qualifications...","TWN":"西餐廚師、中餐廚師、日餐廚師、糕點大師、巧克力大師……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"언제 어디서든 아가씨께 최고의 음식을 대접하기 위해, 관련 자격증은 전부 취득했습니다.","JPN":"いつ、どこでもお嬢様に最高の一皿を召し上がっていただくために、それに関連する免許はすべて取得しています。","ENG":"All to ensure that I can serve Lady Elizabeth the finest dishes anytime, anywhere.","TWN":"無論何時何地，為了給小姐奉上最美味的食物，我已經取得了所有相關的資格證書。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"어쩜, 열정이 대단하시네요. 실은, 저도 요리하는 걸 좋아하거든요.","JPN":"まあ、素晴らしい情熱です。実は、私も料理をするのは好きなんです。","ENG":"I admire your passion. You see, I also like to cook.","TWN":"哇，你的熱情真是令人欽佩。其實，我也喜歡做料理呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"물론, 라이언 씨보다 대단한 실력은 아니지만요…….","JPN":"もちろん、ライアンさんほどの実力はありませんけど……","ENG":"Although I'm not as great as you, Ryan...","TWN":"當然，比不上瑞安先生的實力……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 과찬입니다. 이거 수녀님 요리도 기대되는군요.","JPN":"はは、褒めすぎです。これは、シスターの料理も楽しみですね。","ENG":"Haha, you flatter me. Now, I'm curious to taste your cooking.","TWN":"哈哈，過獎了。我也很期待你的料理呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"저, 그래서 말인데요, 라이언 씨…….","JPN":"あの、それでなんですけど。ライアンさん……","ENG":"Well, since you mentioned it, Ryan...","TWN":"那個……那個……瑞安……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"갑자기 이런 부탁을 하는 게 실례가 되는 줄은 알지만…….","JPN":"いきなりこんなことを頼むのは失礼とはわかっていますけど……","ENG":"I know it's rude to suddenly ask for a favor, but...","TWN":"我知道突然提出這樣的請求很失禮……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"사실, 이번 성탄제에 어떤 요리를 내놓아야 좋을지 줄곧 고민하고 있었거든요.","JPN":"実は、今回の聖誕祭にどんな料理を出したらいいのか、ずっと悩んでいるのです。","ENG":"I have been pondering what dishes I should serve at the Christmas party.","TWN":"其實，我一直在思考這次聖誕節該準備什麼料理比較好。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"혹시 라이언 씨는 성탄절에 어울리는 요리를 알고 계신가요?","JPN":"ライアンさんは、聖誕祭に相応しい料理を知っていますか？","ENG":"Do you know any dishes that are suitable for one?","TWN":"請問瑞安先生知道適合聖誕節的料理嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"글쎄요. 성탄절이라…….","JPN":"そうですね……聖誕祭ですか。","ENG":"Hmm... A Christmas party, you say...?","TWN":"這個嘛……聖誕節嘛……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"역시 크리스마스라면 달콤한 디저트가 어울리지 않겠습니까?","JPN":"やはりクリスマスなら甘いデザートが良いのではないでしょうか？","ENG":"I believe a sweet dessert will be a good choice.","TWN":"果然聖誕節就應該配上甜美的甜點，不是嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"디저트라니… 이거 난감하네요.","JPN":"デザート……困りましたね。","ENG":"A dessert...? Well, this is embarrassing to admit, but...","TWN":"甜點嗎……這可真讓人為難啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"디저트는 제가 한 번도 만들어 본적이 없거든요.","JPN":"私は一度もデザートを作ってみたことがないんです。","ENG":"I've never made desserts before.","TWN":"我從來沒有做過甜點呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"혹시 수녀님께서 괜찮으시다면, 제가 레시피를 하나 가르쳐 드려도 괜찮겠습니까?","JPN":"もしシスターさえよろしければ、私がレシピを一つ教えて差し上げましょうか？","ENG":"If it is okay with you, Sister, would you like to learn a recipe from me?","TWN":"如果你不介意的話，我可以教你一個食譜嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"네? 레시피라고요?","JPN":"えっ？　レシピですか？","ENG":"What? A recipe?","TWN":"啊？你說的是配方嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 페리어 가문 대대로 내려오는 소중한 레시피가 있습니다.","JPN":"はい。フェリエー家に代々伝わる貴重なレシピがあります。","ENG":"Yes. There is a treasured recipe that has been passed down to the Ferrier family for generations.","TWN":"是的，我們佩里家族世代相傳的珍貴食譜。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"이건, 함박눈이 새하얗게 떨어지는 화이트 크리스마스의 밤…….","JPN":"これは、真っ白な綿雪の降るホワイトクリスマスの夜……","ENG":"It is... a special, sweet dessert that you would share with your friends and family on a white Christmas night,","TWN":"這是一個大雪紛飛的白色聖誕夜……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"벽난로를 쬐며 다 함께 나누어 먹었을 때, 가장 특별하고 달콤한 디저트라고 할 수 있죠.","JPN":"暖炉に当たりながらみんなで食べれば、何よりも特別で甘いデザートとなるでしょう。","ENG":"...gathered around the fireplace as soft snowflakes fall outside.","TWN":"圍坐在壁爐旁一起分享時，可以說是最特別、最甜美的點心。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"물론, 눈이 오지 않더라도 그 맛은 보장해드릴 수 있습니다만.","JPN":"もちろん、雪が降らなくともその味は保証できます。","ENG":"Of course, it will still be delicious regardless if it snows or not.","TWN":"當然，即使不下雪，我也能給那個味道打包票。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그, 그거예요……!","JPN":"そ、それです……！","ENG":"Th-this is it...!","TWN":"那、那個啊……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"제가 찾던 요리가 바로 함께 나누어 먹었을 때, 가장 맛있는 요리였거든요!","JPN":"私が探していた料理は、みんなで食べると一番美味しい料理だったんです！","ENG":"I was looking for a dish that became even more delicious when shared with others!","TWN":"我一直在尋找的料理，正是那種一起分享時最美味的料理！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"후훗, 어쩌면 오늘 이곳에서 라이언 씨를 만난 건, 주님의 큰 뜻일지도 모르겠네요.","JPN":"ふふっ、もしかしたら今日ここでライアンさんに出会ったのは、神のご意志だったのかもしれませんね。","ENG":"Haha, maybe it was the Lord's will that I came here and met you, Ryan.","TWN":"呵呵，或許今天在這裡遇見瑞安先生，也是主的意思吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 수녀님께 도움이 될 수 있어서 다행이로군요.","JPN":"はは、シスターの役に立ててよかったです。","ENG":"Haha, I am glad that I was of help to you, Sister.","TWN":"哈哈，能幫到你真是太好了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그래서… 화이트 크리스마스에 어울린다는 그 디저트는 어떤 디저트인가요?","JPN":"それで……ホワイトクリスマスにぴったりなデザートとはどんなデザートなのですか？","ENG":"So... what kind of dessert is it that suits a white Christmas?","TWN":"所以……適合白色聖誕節的甜點是什麼呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그 디저트의 이름은…….","JPN":"そのデザートの名前は……","ENG":"It's called...","TWN":"那個甜點的名字是……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>쇼콜라 무스 케이크</color>라고 합니다.","JPN":"<color=#ffd34c>ムースショコラ</color>と言います。","ENG":"a <color=#ffd34c>chocolate mousse cake</color>.","TWN":"<color=#ffd34c>巧克力慕斯蛋糕</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};